character 'x'  is not present, the string is returned unchanged.
char* cut_after_x(char *s) {
  size_t len = 0;
  for (const char * p = s; *p != '\0' && *p != 'x'; ++p) {
      len++;
  }
  char *result = malloc(len); 
  if (!result) return NULL; 
  for (size_t i = 0; i < len; i++) {
      result[i] = s[i];
  }
  return result;
}
